#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_PROCESSES 10
#define MAX_RESOURCES 10
#define MAX_NAME_LEN 20

// Structure to represent a process
typedef struct {
 char name[MAX_NAME_LEN];
 int id;
} Process;

// Structure to represent a resource
typedef struct {
 char name[MAX_NAME_LEN];
 int id;
 int instances; // Number of instances
} Resource;

// Graph representation using adjacency list
typedef struct {
 int vertices;
 int adj[MAX_PROCESSES * 2][MAX_PROCESSES * 2];
 char vertex_names[MAX_PROCESSES * 2][MAX_NAME_LEN];
} Graph;

// System state
typedef struct {
 Process processes[MAX_PROCESSES];
 Resource resources[MAX_RESOURCES];
 int num_processes;
 int num_resources;

 // Allocation matrix: allocation[p][r] = 1 if process p holds resource r
 int allocation[MAX_PROCESSES][MAX_RESOURCES];

 // Request matrix: request[p][r] = 1 if process p requests resource r
 int request[MAX_PROCESSES][MAX_RESOURCES];
} SystemState;

// Initialize system state
void init_system(SystemState *sys) {
 sys->num_processes = 0;
 sys->num_resources = 0;

 // Initialize matrices to 0
 for (int i = 0; i < MAX_PROCESSES; i++) {
 for (int j = 0; j < MAX_RESOURCES; j++) {
 sys->allocation[i][j] = 0;
 sys->request[i][j] = 0;
 }
 }
}

// Add a process to the system
int add_process(SystemState *sys, const char *name) {
 if (sys->num_processes >= MAX_PROCESSES) {
 return -1;
 }
 strcpy(sys->processes[sys->num_processes].name, name);
 sys->processes[sys->num_processes].id = sys->num_processes;
 return sys->num_processes++;
}

// Add a resource to the system
int add_resource(SystemState *sys, const char *name, int instances) {
 if (sys->num_resources >= MAX_RESOURCES) {
 return -1;
 }
 strcpy(sys->resources[sys->num_resources].name, name);
 sys->resources[sys->num_resources].id = sys->num_resources;
 sys->resources[sys->num_resources].instances = instances;
 return sys->num_resources++;
}

// Set allocation: process p holds resource r
void set_allocation(SystemState *sys, int p, int r) {
 if (p < sys->num_processes && r < sys->num_resources) {
 sys->allocation[p][r] = 1;
 }
}

// Set request: process p requests resource r
void set_request(SystemState *sys, int p, int r) {
 if (p < sys->num_processes && r < sys->num_resources) {
 sys->request[p][r] = 1;
 }
}

// Build Wait-For Graph from allocation and request matrices
// Returns adjacency matrix for processes
void build_wait_for_graph(SystemState *sys, Graph *wfg) {
 wfg->vertices = sys->num_processes;

 // Initialize adjacency matrix to 0
 for (int i = 0; i < MAX_PROCESSES * 2; i++) {
 for (int j = 0; j < MAX_PROCESSES * 2; j++) {
 wfg->adj[i][j] = 0;
 }
 strcpy(wfg->vertex_names[i], "");
 }

 // Name vertices
 for (int i = 0; i < sys->num_processes; i++) {
 strcpy(wfg->vertex_names[i], sys->processes[i].name);
 }

 // For each process, find what it's waiting for
 for (int p = 0; p < sys->num_processes; p++) {
 for (int r = 0; r < sys->num_resources; r++) {
 // If process requests resource r
 if (sys->request[p][r]) {
 // Find process that holds resource r
 for (int holder = 0; holder < sys->num_processes; holder++) {
 if (sys->allocation[holder][r]) {
 // p is waiting for holder
 wfg->adj[p][holder] = 1;
 }
 }
 }
 }
 }
}

// DFS for cycle detection
bool dfs_cycle(Graph *wfg, int node, int visited[], int rec_stack[], 
 int path[], int *path_len, int *cycle_start) {
 visited[node] = 1;
 rec_stack[node] = 1;
 path[(*path_len)++] = node;

 for (int neighbor = 0; neighbor < wfg->vertices; neighbor++) {
 if (wfg->adj[node][neighbor]) {
 if (!visited[neighbor]) {
 if (dfs_cycle(wfg, neighbor, visited, rec_stack, path, path_len, cycle_start)) {
 return true;
 }
 } else if (rec_stack[neighbor]) {
 // Found cycle
 *cycle_start = -1;
 for (int i = 0; i < *path_len; i++) {
 if (path[i] == neighbor) {
 *cycle_start = i;
 break;
 }
 }
 return true;
 }
 }
 }

 rec_stack[node] = 0;
 (*path_len)--;
 return false;
}

// Detect deadlock using Wait-For Graph
bool detect_deadlock(SystemState *sys, int deadlocked_procs[], int *count) {
 Graph wfg;
 build_wait_for_graph(sys, &wfg);

 int visited[MAX_PROCESSES * 2] = {0};
 int rec_stack[MAX_PROCESSES * 2] = {0};
 int path[MAX_PROCESSES * 2];
 int path_len = 0;
 int cycle_start;

 *count = 0;

 // Try DFS from each unvisited node
 for (int i = 0; i < wfg.vertices; i++) {
 if (!visited[i]) {
 path_len = 0;
 if (dfs_cycle(&wfg, i, visited, rec_stack, path, &path_len, &cycle_start)) {
 // Found deadlock
 printf("\n=== Deadlock Detected! ===\n");
 printf("Cycle found: ");
 for (int j = cycle_start; j < path_len; j++) {
 printf("%s ", wfg.vertex_names[path[j]]);
 if (j < path_len - 1) printf("-> ");
 deadlocked_procs[*count] = path[j];
 (*count)++;
 }
 printf("\n");
 return true;
 }
 }
 }

 printf("\n=== No Deadlock Detected ===\n");
 return false;
}

// Print system state
void print_state(SystemState *sys) {
 printf("\n=== System State ===\n");
 printf("Processes: ");
 for (int i = 0; i < sys->num_processes; i++) {
 printf("%s ", sys->processes[i].name);
 }
 printf("\nResources: ");
 for (int i = 0; i < sys->num_resources; i++) {
 printf("%s(%d) ", sys->resources[i].name, sys->resources[i].instances);
 }

 printf("\n\nAllocation Matrix:\n");
 printf(" ");
 for (int j = 0; j < sys->num_resources; j++) {
 printf("%6s", sys->resources[j].name);
 }
 printf("\n");

 for (int i = 0; i < sys->num_processes; i++) {
 printf("%6s:", sys->processes[i].name);
 for (int j = 0; j < sys->num_resources; j++) {
 printf("%6d", sys->allocation[i][j]);
 }
 printf("\n");
 }

 printf("\nRequest Matrix:\n");
 printf(" ");
 for (int j = 0; j < sys->num_resources; j++) {
 printf("%6s", sys->resources[j].name);
 }
 printf("\n");

 for (int i = 0; i < sys->num_processes; i++) {
 printf("%6s:", sys->processes[i].name);
 for (int j = 0; j < sys->num_resources; j++) {
 printf("%6d", sys->request[i][j]);
 }
 printf("\n");
 }
}

int main() {
 SystemState sys;
 init_system(&sys);

 // Add processes: P1 and P2
 add_process(&sys, "P1");
 add_process(&sys, "P2");

 // Add resources: R1 (disk), R2 (printer)
 add_resource(&sys, "R1", 1); // 1 instance
 add_resource(&sys, "R2", 1); // 1 instance

 // Setup deadlock scenario:
 // P1 holds R1, requests R2
 // P2 holds R2, requests R1
 set_allocation(&sys, 0, 0); // P1 holds R1
 set_request(&sys, 0, 1); // P1 requests R2

 set_allocation(&sys, 1, 1); // P2 holds R2
 set_request(&sys, 1, 0); // P2 requests R1

 // Print the system state
 print_state(&sys);

 // Detect deadlock
 int deadlocked[10];
 int count;
 bool has_deadlock = detect_deadlock(&sys, deadlocked, &count);

 if (has_deadlock) {
 printf("\nDeadlocked processes: ");
 for (int i = 0; i < count; i++) {
 printf("%s ", sys.processes[deadlocked[i]].name);
 }
 printf("\n\nExplanation:\n");
 printf("- P1 holds R1 (disk) and requests R2 (printer)\n");
 printf("- P2 holds R2 (printer) and requests R1 (disk)\n");
 printf("- Circular wait condition exists!\n");
 }

 return 0;
}
